// Merge transcription from either Whisper or ElevenLabs
const whisperResult = $('Whisper STT - Transcribe Audio').first()?.json;
const elevenLabsResult = $('ElevenLabs STT - Alt Transcription').first()?.json;
const config = $('Set Business Config').first().json;

const transcribedText =
  whisperResult?.text ||
  elevenLabsResult?.text ||
  elevenLabsResult?.transcription ||
  'Could not transcribe audio.';

return {
  json: {
    ...config,
    transcribedText,
    transcriptionSource: whisperResult?.text ? 'whisper' : 'elevenlabs',
    transcriptionTimestamp: new Date().toISOString()
  }
};

