const item = $input.item.json;
const config = $('JS - Merge Transcription Result').first().json;

// Parse AI response
let extracted = {};
try {
  const rawContent = item.choices?.[0]?.message?.content || '{}';
  extracted = JSON.parse(rawContent);
} catch (e) {
  extracted = {
    callerName: 'Unknown',
    callerPhone: config.callerPhone,
    requestedService: 'General Consultation',
    requestedDate: config.todayDate,
    requestedTime: '10:00',
    requestedTimeRaw: '10:00 AM',
    notes: '',
    intentConfidence: 'low',
    isBookingRequest: true
  };
}

// Build ISO datetime for the requested slot
const slotDateTime = `${extracted.requestedDate}T${extracted.requestedTime}:00`;
const slotEndTime = new Date(new Date(slotDateTime).getTime() + config.slotDurationMinutes * 60000).toISOString();

return {
  json: {
    ...config,
    ...extracted,
    callerPhone: extracted.callerPhone || config.callerPhone,
    slotStart: slotDateTime,
    slotEnd: slotEndTime,
    transcribedText: config.transcribedText
  }
};

const item = $input.item.json;
const config = $('JS - Parse Extracted Intent').first().json;

// Get Cal.com slots
const calSlots = $('Cal.com - Check Available Slots').first()?.json;
const googleEvents = $('Google Calendar - Check Busy Times').first()?.json;

// Extract available times from Cal.com response
const calAvailableSlots = [];
if (calSlots?.slots) {
  const dateKey = Object.keys(calSlots.slots)[0];
  const slots = calSlots.slots[dateKey] || [];
  slots.forEach(s => calAvailableSlots.push(s.time || s));
}

// Extract busy times from Google Calendar
const busyTimes = (googleEvents?.items || []).map(e => ({
  start: e.start?.dateTime || e.start?.date,
  end: e.end?.dateTime || e.end?.date
}));

// Check if requested slot is available
const requestedStart = new Date(config.slotStart);
const requestedEnd = new Date(config.slotEnd);

const isConflict = busyTimes.some(b => {
  const bStart = new Date(b.start);
  const bEnd = new Date(b.end);
  return requestedStart < bEnd && requestedEnd > bStart;
});

// Find next 3 available Cal.com slots if conflict
const suggestedSlots = calAvailableSlots
  .filter(s => new Date(s) > new Date())
  .slice(0, 3);

const isAvailable = !isConflict && (
  calAvailableSlots.length === 0 ||
  calAvailableSlots.some(s => s.startsWith(config.requestedTime.substring(0, 5)) || Math.abs(new Date(s) - requestedStart) < 900000)
);

return {
  json: {
    ...config,
    isAvailable,
    isConflict,
    suggestedSlots,
    availableSlotCount: calAvailableSlots.length,
    busySlotCount: busyTimes.length
  }
};

