const item = $input.item.json;
const config = $('JS - Evaluate Slot Availability').first().json;

// Determine if we came from booking success or conflict path
const bookingData = $('Cal.com - Book the Appointment').first()?.json;
const conflictAI = $('AI - Generate Conflict Response').first()?.json;

let confirmationText = '';
let bookingStatus = '';
let bookingRef = '';

if (bookingData?.uid || bookingData?.id) {
  // Successful booking
  bookingRef = bookingData.uid || bookingData.id || 'N/A';
  bookingStatus = 'CONFIRMED';
  confirmationText = `✅ Appointment Confirmed!

Hi ${config.callerName},

Your appointment has been booked at ${config.businessName}.

📋 Details:
• Service: ${config.requestedService}
• Date: ${config.requestedDate}
• Time: ${config.requestedTimeRaw}
• Ref: ${bookingRef}

Please arrive 5 minutes early. Reply CANCEL to cancel.`;
} else {
  // Conflict - use AI suggested response
  bookingStatus = 'CONFLICT';
  const aiMsg = conflictAI?.choices?.[0]?.message?.content || `Sorry, ${config.requestedTimeRaw} on ${config.requestedDate} is not available. Please call us to reschedule.`;
  confirmationText = `⚠️ Slot Unavailable\n\n${aiMsg}`;
}

return {
  json: {
    ...config,
    confirmationText,
    bookingStatus,
    bookingRef,
    bookedAt: new Date().toISOString()
  }
};
